using System.Collections;
using UnityEngine;

// Ataques de contacto/melee e ataques que deslocam o próprio inimigo (Etapa
// 2.1). Cada subclasse [System.Serializable] é seleccionável no Inspector via
// PolymorphicListDrawer (prefixo "Attack_" removido no menu — ver
// EnemyAttackControllerEditor).

/// <summary>Garra curta: dano de contacto sem deslocar o inimigo. Verifica o alcance novamente no momento do ataque (depois do telegraph).</summary>
[System.Serializable]
public class Attack_ClawShort : EnemyAttack
{
    [Header("Garra")]
    [Tooltip("Distância ao alvo considerada 'acertou', verificada no fim do telegraph.")]
    public float hitRange = 1f;

    public Attack_ClawShort()
    {
        attackName = "Garra";
        range = 1.2f;
        prepTime = 0.15f;
        recoveryTime = 0.3f;
        cooldown = 1f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (ctx.IsTargetWithin(ctx.transform.position, hitRange))
            ctx.DamagePlayer(damage, knockbackForce);

        yield break;
    }
}

/// <summary>Mordida curta: como a Garra, mas com um pequeno avanço (lunge) na direcção do alvo antes de morder.</summary>
[System.Serializable]
public class Attack_BiteShort : EnemyAttack
{
    [Header("Mordida")]
    public float hitRange = 0.8f;

    [Tooltip("Velocidade do pequeno avanço na direcção do alvo (0 = sem avanço).")]
    public float lungeSpeed = 3f;

    [Tooltip("Duração do avanço, em segundos.")]
    public float lungeDuration = 0.1f;

    public Attack_BiteShort()
    {
        attackName = "Mordida";
        range = 1f;
        prepTime = 0.2f;
        recoveryTime = 0.25f;
        cooldown = 0.8f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        var rb = ctx.Rb;

        if (rb != null && lungeSpeed > 0f)
        {
            float dir = Mathf.Sign(ctx.DirectionToTarget().x);
            float elapsed = 0f;

            while (elapsed < lungeDuration)
            {
                rb.velocity = new Vector2(dir * lungeSpeed, rb.velocity.y);
                elapsed += Time.deltaTime;
                yield return null;
            }

            rb.velocity = new Vector2(0f, rb.velocity.y);
        }

        if (ctx.IsTargetWithin(ctx.transform.position, hitRange))
            ctx.DamagePlayer(damage, knockbackForce);
    }
}

/// <summary>Investida horizontal: o inimigo lança-se na horizontal em direcção ao alvo durante "dashDuration", causando dano se o tocar.</summary>
[System.Serializable]
public class Attack_HorizontalDash : EnemyAttack
{
    [Header("Investida")]
    public float dashSpeed = 8f;
    public float dashDuration = 0.35f;

    [Tooltip("Distância ao alvo considerada 'acertou' durante a investida.")]
    public float hitRadius = 0.6f;

    public Attack_HorizontalDash()
    {
        attackName = "Investida";
        range = 5f;
        minRange = 1.5f;
        prepTime = 0.25f;
        recoveryTime = 0.4f;
        cooldown = 2f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        var rb = ctx.Rb;
        float dir = Mathf.Sign(ctx.DirectionToTarget().x);
        bool hit = false;
        float elapsed = 0f;

        while (elapsed < dashDuration)
        {
            if (rb != null) rb.velocity = new Vector2(dir * dashSpeed, rb.velocity.y);

            if (!hit && ctx.IsTargetWithin(ctx.transform.position, hitRadius))
            {
                hit = true;
                ctx.DamagePlayer(damage, knockbackForce);
            }

            elapsed += Time.deltaTime;
            yield return null;
        }

        if (rb != null) rb.velocity = new Vector2(0f, rb.velocity.y);
    }
}

/// <summary>Salto em direcção ao player: aplica um impulso de salto com componente horizontal apontada ao alvo, causando dano se o tocar enquanto está no ar.</summary>
[System.Serializable]
public class Attack_JumpAtPlayer : EnemyAttack
{
    [Header("Salto")]
    public float jumpSpeedX = 4f;
    public float jumpHeight = 6f;

    [Tooltip("Tempo total no ar (Execute termina ao fim deste tempo; a aterragem/queda é tratada pela física normal durante Recuperando).")]
    public float airTime = 0.8f;

    [Tooltip("Distância ao alvo considerada 'acertou' enquanto no ar.")]
    public float hitRadius = 0.7f;

    public Attack_JumpAtPlayer()
    {
        attackName = "Salto";
        range = 4f;
        usableOnGround = true;
        prepTime = 0.2f;
        recoveryTime = 0.3f;
        cooldown = 1.5f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        var rb = ctx.Rb;
        if (rb == null) yield break;

        float dir = Mathf.Sign(ctx.DirectionToTarget().x);
        rb.velocity = new Vector2(dir * jumpSpeedX, jumpHeight);

        bool hit = false;
        float elapsed = 0f;

        while (elapsed < airTime)
        {
            if (!hit && ctx.IsTargetWithin(ctx.transform.position, hitRadius))
            {
                hit = true;
                ctx.DamagePlayer(damage, knockbackForce);
            }

            elapsed += Time.deltaTime;
            yield return null;
        }
    }
}

/// <summary>Ataque cima-para-baixo: para inimigos voadores/flutuantes — desce a alta velocidade e causa dano em área no impacto.</summary>
[System.Serializable]
public class Attack_SlamDown : EnemyAttack
{
    [Header("Ataque Cima-Para-Baixo")]
    [Tooltip("Velocidade de queda durante o ataque (m/s, positivo).")]
    public float slamSpeed = 14f;

    public float maxFallTime = 1f;

    [Tooltip("Raio do impacto no fim da queda (dano em área).")]
    public float impactRadius = 1.5f;

    public Attack_SlamDown()
    {
        attackName = "Mergulho";
        range = 6f;
        usableOnGround = false;
        usableInAir = true;
        prepTime = 0.3f;
        recoveryTime = 0.5f;
        cooldown = 2.5f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        var rb = ctx.Rb;
        bool hit = false;
        float elapsed = 0f;

        while (elapsed < maxFallTime)
        {
            if (rb != null) rb.velocity = new Vector2(rb.velocity.x, -slamSpeed);

            if (!hit && ctx.IsTargetWithin(ctx.transform.position, impactRadius))
            {
                hit = true;
                ctx.DamagePlayer(damage, knockbackForce, Vector2.up);
            }

            elapsed += Time.deltaTime;
            yield return null;
        }

        // Impacto final: dano em área mesmo que o alvo só tenha entrado no raio agora.
        if (!hit && ctx.IsTargetWithin(ctx.transform.position, impactRadius))
            ctx.DamagePlayer(damage, knockbackForce, Vector2.up);

        if (rb != null) rb.velocity = new Vector2(rb.velocity.x, 0f);
    }
}

/// <summary>Empurrão sem dano: afasta o player com um impulso de velocidade, sem causar dano (GDD 12.2 — Robô de limpeza).</summary>
[System.Serializable]
public class Attack_Push : EnemyAttack
{
    [Header("Empurrão")]
    [Tooltip("Distância ao alvo considerada 'acertou'.")]
    public float hitRadius = 1.2f;

    [Tooltip("Velocidade aplicada ao player na direcção do empurrão.")]
    public float pushForce = 6f;

    public Attack_Push()
    {
        attackName = "Empurrão";
        range = 1.5f;
        damage = 0; // "empurrão sem dano" (GDD — Etapa 2.1)
        prepTime = 0.2f;
        recoveryTime = 0.3f;
        cooldown = 1.2f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (ctx.IsTargetWithin(ctx.transform.position, hitRadius))
        {
            Vector2 away = (Vector2)ctx.Target.position - (Vector2)ctx.transform.position;
            ctx.PushPlayer(pushForce, away);
        }

        yield break;
    }
}

/// <summary>Ataque que puxa o player na direcção do inimigo (ex: "anzol" do boss Maré de Rede — GDD 12.3.5), causando dano ao chegar perto.</summary>
[System.Serializable]
public class Attack_Pull : EnemyAttack
{
    [Header("Puxar (Anzol)")]
    public float pullSpeed = 5f;
    public float pullDuration = 0.8f;

    [Tooltip("Distância ao inimigo considerada 'chegou' — dano ao chegar.")]
    public float arriveDistance = 1f;

    public Attack_Pull()
    {
        attackName = "Anzol";
        range = 6f;
        minRange = 1.5f;
        requiresLineOfSight = true;
        prepTime = 0.4f;
        recoveryTime = 0.5f;
        cooldown = 3f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        float elapsed = 0f;

        while (elapsed < pullDuration)
        {
            if (ctx.Target == null) yield break;

            Vector2 toSelf = (Vector2)ctx.transform.position - (Vector2)ctx.Target.position;
            float dist = toSelf.magnitude;

            if (dist <= arriveDistance)
            {
                ctx.DamagePlayer(damage, knockbackForce);
                yield break;
            }

            ctx.PullPlayer(pullSpeed, toSelf.normalized);

            elapsed += Time.deltaTime;
            yield return null;
        }
    }
}
